mapper.update:
update assistant_sessions
set last_message_at = #{lastMessageAt},
    updated_at = #{lastMessageAt}
where id = #{sessionId}
  and user_id = #{userId}
  and status <> 'DELETED'

update assistant_sessions
set title = #{title},
    updated_at = #{updatedAt}
where id = #{sessionId}
  and user_id = #{userId}
  and status <> 'DELETED'

update assistant_sessions
set current_instruction_profile_id=#{instructionProfileId}, updated_at=#{updatedAt}
where id=#{sessionId} and user_id=#{userId} and status <> 'DELETED'

update assistant_sessions
set current_model_connection_id=#{connectionId}, current_model_id=#{modelId}, updated_at=#{updatedAt}
where id=#{sessionId} and user_id=#{userId} and status <> 'DELETED'

mapper.delete:
delete from assistant_sessions
where id = #{sessionId}
  and user_id = #{userId}
